import pickle
import pandas as pd
from collections import defaultdict, deque

d=pickle.load(open('parsed.pkl','rb'))
orders,supplier,whseq,storerecv=d['orders'],d['supplier'],d['whseq'],d['storerecv']
DAYS=365; PRODUCTS=[f'P_{i}' for i in range(1,31)]
STORES=[f'S_{i}' for i in range(1,11)]; PRODUCERS=[f'PR_{i}' for i in range(1,61)]

# --- rebuild wholesaler allocation (producer breakdown to each store/product/day) ---
def wh_alloc():
    wh=defaultdict(deque)
    alloc={}
    for day in range(1,DAYS+1):
        for pr in sorted(PRODUCERS, key=lambda pr: whseq.get((day,pr),10**9)):
            for p,q in supplier.get((day,pr),{}).items():
                if q>0: wh[p].append([pr,q])
        sts=[s for s in STORES if (day,s) in storerecv]
        sts.sort(key=lambda s: storerecv[(day,s)][0])
        for s in sts:
            for p,need in orders.get((day,s),{}).items():
                if need<=0: continue
                q=wh[p]; got=[]
                while need>0 and q:
                    b=q[0]; take=min(b[1],need); got.append((b[0],take)); b[1]-=take; need-=take
                    if b[1]==0: q.popleft()
                if got: alloc[(day,s,p)]=got
    return alloc
alloc=wh_alloc()
print("alloc entries:", len(alloc))

# --- daily sold per (store,product) from agg ---
g=pd.read_pickle('agg.pkl')
sold=defaultdict(int)
for r in g.itertuples(index=False):
    sold[(r.Day,r.Store_ID,r.Product_ID)]=int(r.sold)

# --- store FIFO: each day SELL first (from prior inventory), then RECEIVE day's delivery ---
# inventory per (store,product): deque of [producer, qty]
consumed={}  # (store,product,day) -> list of (producer, qty_sold) in FIFO order
inv=defaultdict(lambda: defaultdict(deque))  # store->product->deque
unmet_sell=0
for day in range(1,DAYS+1):
    for s in STORES:
        for p in PRODUCTS:
            need=sold.get((day,s,p),0)
            if need>0:
                q=inv[s][p]; got=[]
                while need>0 and q:
                    b=q[0]; take=min(b[1],need); got.append((b[0],take)); b[1]-=take; need-=take
                    if b[1]==0: q.popleft()
                if need>0: unmet_sell+=need  # sold more than we have in model -> error
                if got: consumed[(s,p,day)]=got
        # receive
        for p in PRODUCTS:
            a=alloc.get((day,s,p))
            if a:
                for pr,qty in a:
                    inv[s][p].append([pr,qty])
print("unmet_sell (should be 0):", unmet_sell)
# leftover inventory at end
leftover=sum(b[1] for s in inv for p in inv[s] for b in inv[s][p])
print("store leftover inventory end:", leftover)

pickle.dump({'consumed':consumed,'alloc':alloc}, open('fifo.pkl','wb'))
print("saved fifo.pkl; consumed entries:", len(consumed))

# segment analysis: distribution of #producers contributing to a single (store,product,day) sale
import collections
nprod=collections.Counter(len(v) for v in consumed.values())
print("\n# of distinct producers per (store,product,day) sale event:")
for k in sorted(nprod): print(f"  {k} producer(s): {nprod[k]} day-events")
