import numpy as np, pickle
from collections import deque
from scipy.optimize import nnls
rng=np.random.RandomState(7)
NP=60; NPROD=12; NS=10; DAYS=365
carries={pr:set(np.where(rng.rand(NPROD)<0.5)[0]) for pr in range(NP)}
for pr in range(NP):
    if not carries[pr]: carries[pr]={int(rng.randint(NPROD))}
# quality per (pr,p) uniform; per-consumer thresholds ~ Normal -> CONTINUUM of badness
quality={(pr,p):rng.rand() for pr in range(NP) for p in carries[pr]}
t=np.arange(DAYS); cal=np.ones((NPROD,DAYS))
for p in range(NPROD):
    st=rng.uniform(0.1,0.4)
    cal[p]=1 - st*np.exp(-((t-200)**2)/(2*35**2)) + st*0.8*(np.exp(-(t**2)/(2*8**2))+np.exp(-((t-364)**2)/(2*8**2)))
M=np.zeros((NS,NPROD),dtype=int); lam={}; cthr={}
for s in range(NS):
    for p in range(NPROD):
        M[s,p]=rng.randint(20,32)
        lam[(s,p)]=rng.uniform(2.0,3.0,size=M[s,p])
        # per-consumer thresholds: only LOW quality producers breach -> tune mean low so rejection partial
        cthr[(s,p)]=np.clip(rng.normal(0.30,0.12,size=M[s,p]),0,1)
# true expected rejection fraction rho(pr,p) = mean over all consumers P(thr>quality)
rho={}
for (pr,p) in quality:
    allthr=np.concatenate([cthr[(s,p)] for s in range(NS)])
    rho[(pr,p)]=(allthr>quality[(pr,p)]).mean()

inv_wh={p:deque() for p in range(NPROD)}
store_inv=[[deque() for _ in range(NPROD)] for _ in range(NS)]
rec=[[np.zeros(M[s,p],dtype=int) for p in range(NPROD)] for s in range(NS)]
def rf(days_left):
    elapsed=14-days_left+1
    return np.where(days_left<=0,1.0,np.where(elapsed<=3,0.2,np.where(elapsed<=7,0.5,0.8)))
demand=np.zeros((NS,NPROD,DAYS)); U=np.zeros((NS,NPROD,NP,DAYS))
for day in range(DAYS):
    for pr in rng.permutation(NP):
        for p in carries[pr]:
            if rng.rand()<0.85:
                inv_wh[p].append([pr,int(rng.randint(10,26)),quality[(pr,p)]])
    for s in rng.permutation(NS):
        for p in range(NPROD):
            need=int(3*lam[(s,p)].sum()*cal[p,day]); q=inv_wh[p]
            while need>0 and q:
                b=q[0]; take=min(b[1],need); store_inv[s][p].append([b[0],take,b[2]]); b[1]-=take; need-=take
                if b[1]==0: q.popleft()
    for s in range(NS):
        for p in range(NPROD):
            d=rng.poisson(lam[(s,p)]*cal[p,day]*rf(rec[s][p]))
            demand[s,p,day]=d.sum()
            inv=store_inv[s][p]
            for c in rng.permutation(M[s,p]):
                want=int(d[c]); 
                if rec[s][p][c]>0: rec[s][p][c]-=1
                if want<=0: continue
                rejected=False
                while want>0 and inv:
                    b=inv[0]; take=min(b[1],want); U[s,p,b[0],day]+=take
                    # consumer rejects if their threshold > quality (per unit; reject if any bad unit)
                    if cthr[(s,p)][c] > b[2]: rejected=True
                    b[1]-=take; want-=take
                    if b[1]==0: inv.popleft()
                if rejected: rec[s][p][c]=14
# deconvolution
deficit=np.zeros(15)
for k in range(1,15): deficit[k]=0.8 if k<=3 else (0.5 if k<=7 else 0.2)
def conv(Uarr):
    X=np.zeros_like(Uarr)
    for k in range(1,15): X[...,k:]+=deficit[k]*Uarr[...,:DAYS-k]
    return X
WARM=15
def calest(dem):
    c=np.zeros((NPROD,DAYS))
    for p in range(NPROD):
        tot=dem[:,p,:].sum(axis=0); c[p]=tot/tot.mean()
    return c
def fit(p,X,c):
    A=[];y=[]
    for s in range(NS):
        for tt in range(WARM,DAYS):
            a=np.zeros(NS+NP); a[s]=c[p,tt]; a[NS:]=-X[s,p,:,tt]; A.append(a); y.append(demand[s,p,tt])
    coef,_=nnls(np.array(A),np.array(y),maxiter=20000); return coef[NS:]
c=calest(demand); X=conv(U)
for it in range(3):
