        b=fit(p,X,c); beta[p]=b; pred[:,p,:]=np.tensordot(b,X[:,p,:,:],axes=([0],[1]))
    c=calest(demand+pred)
import pandas as pd
rows=[]
for p in range(NPROD):
    for pr in range(NP):
        if p in carries[pr]:
            rows.append((p,pr,beta[p,pr],rho[(pr,p)],quality[(pr,p)]))
R=pd.DataFrame(rows,columns=['p','pr','beta','rho','q'])
print("rho (true rejection fraction) distribution:", np.round(R['rho'].describe().values,3))
print("\nbeta vs rho: bin by rho")
for lo,hi in [(0,0.001),(0.001,0.02),(0.02,0.05),(0.05,0.1),(0.1,0.2),(0.2,0.4),(0.4,1)]:
    sub=R[(R['rho']>=lo)&(R['rho']<hi)]
    if len(sub): print(f"  rho[{lo},{hi}): n={len(sub):3d} beta mean={sub['beta'].mean():.3f} median={sub['beta'].median():.3f} max={sub['beta'].max():.3f}")
print("\nNOISE FLOOR: beta among true-innocent (rho==0):")
innoc=R[R['rho']==0]
print(f"  n={len(innoc)} beta max={innoc['beta'].max():.4f} 95pct={innoc['beta'].quantile(.95):.4f} mean={innoc['beta'].mean():.4f}")
print("\ncorr(beta,rho):", R[['beta','rho']].corr().iloc[0,1].round(3))
R.to_pickle('synth2_R.pkl')
