import pandas as pd, numpy as np, pickle
from scipy.optimize import nnls
g=pd.read_pickle('agg.pkl')
PRODS=[f'P_{i}' for i in range(1,31)]; STORES=[f'S_{i}' for i in range(1,11)]
PRODUCERS=[f'PR_{i}' for i in range(1,61)]; pr_ix={pr:i for i,pr in enumerate(PRODUCERS)}
fifo=pickle.load(open('fifo.pkl','rb')); consumed=fifo['consumed']
DAYS=365
sidx={s:i for i,s in enumerate(STORES)}; pidx={p:i for i,p in enumerate(PRODS)}
dem=np.zeros((10,30,DAYS))
for r in g.itertuples(index=False): dem[sidx[r.Store_ID],pidx[r.Product_ID],r.Day-1]=r.demand
U=np.zeros((10,30,60,DAYS))
for (s,p,day),lst in consumed.items():
    for pr,qty in lst: U[sidx[s],pidx[p],pr_ix[pr],day-1]+=qty
D=pickle.load(open('deconv2.pkl','rb')); beta=D['beta']; base=D['base']; cal=D['cal']
deficit=np.zeros(15)
for k in range(1,15): deficit[k]=0.8 if k<=3 else (0.5 if k<=7 else 0.2)
def conv(Uarr):
    X=np.zeros_like(Uarr)
    for k in range(1,15): X[...,k:]+=deficit[k]*Uarr[...,:DAYS-k]
    return X
X=conv(U); WARM=15
def fit_product(pi,Xarr,demarr):
    A=[];y=[]
    for si in range(10):
        for t in range(WARM,DAYS):
            a=np.zeros(70); a[si]=cal[pi,t]; a[10:]=-Xarr[si,pi,:,t]; A.append(a); y.append(demarr[si,pi,t])
    coef,_=nnls(np.array(A),np.array(y),maxiter=10000); return coef[10:]
resid_std=np.zeros((10,30))
for pi,p in enumerate(PRODS):
    pred_def=np.tensordot(beta[p],X[:,pi,:,:],axes=([0],[1]))
    model=base[p][:,None]*cal[pi][None,:]-pred_def
    resid_std[:,pi]=(dem[:,pi,:]-model)[:,WARM:].std(axis=1)

# ---- iterative leakage floor at SEED=0.05 ----
rng=np.random.RandomState(2); SEED=0.05; nrep=6
seed_set={p:set(np.where(beta[p]>=SEED)[0]) for p in PRODS}
innoc=[]; seedb=[]
for rep in range(nrep):
    simdem=np.zeros((10,30,DAYS))
    for pi,p in enumerate(PRODS):
        bb=np.zeros(60)
        for i in seed_set[p]: bb[i]=beta[p][i]
        model=base[p][:,None]*cal[pi][None,:]-np.tensordot(bb,X[:,pi,:,:],axes=([0],[1]))
        simdem[:,pi,:]=np.maximum(model+rng.normal(0,resid_std[:,pi][:,None],size=(10,DAYS)),0)
    for pi,p in enumerate(PRODS):
        b=fit_product(pi,X,simdem)
        for i in range(60):
            (seedb if i in seed_set[p] else innoc).append(b[i])
innoc=np.array(innoc); seedb=np.array(seedb)
print(f"SEED={SEED}: innocent leakage floor max={innoc.max():.4f} 99pct={np.percentile(innoc,99):.4f}; seed recovered min={seedb.min():.4f}")

# ---- event-alignment dip score for every (pr,p) (independent of beta) ----
calt=cal
def residual(pi):
    R=np.zeros((10,DAYS))
    for si in range(10):
        x=dem[si,pi,:]/calt[pi]; bb=np.median(x); R[si]=dem[si,pi,:]/(bb*calt[pi])
    return R
dipscore=np.zeros((30,60))
for pi in range(30):
    R=residual(pi)
    for pri in range(60):
        num=0.0; den=0.0; pre=0.0; pren=0.0
        for si in range(10):
